// Parsear respuesta de Gemini y preparar posts
const response = $input.first().json;
const campaignId = $('Create Campaign Record').first().json.id;
const webhookData = $('Webhook').first().json.body;
const startDate = new Date();

let calendar;
try {
  const text = response.candidates[0].content.parts[0].text;
  calendar = JSON.parse(text);
} catch (e) {
  // Intentar extraer JSON de texto
  const text = response.candidates[0].content.parts[0].text;
  const match = text.match(/\[.*\]/s);
  if (match) {
    calendar = JSON.parse(match[0]);
  } else {
    throw new Error('No se pudo parsear el calendario de Gemini: ' + e.message);
  }
}

// Generar posts con fechas programadas
const posts = calendar.map((item, index) => {
  const postDate = new Date(startDate);
  postDate.setDate(postDate.getDate() + (item.day - 1));

  return {
    json: {
      campaign_id: campaignId,
      day_number: item.day,
      post_type: item.type,
      caption: item.caption,
      caption_x: item.caption_x || item.caption.substring(0, 277) + '...',
      hashtags: item.hashtags || [],
      image_prompt: item.image_prompt,
      scheduled_date: postDate.toISOString().split('T')[0],
      scheduled_time: item.time + ':00',
      platforms: webhookData.platforms || ['facebook', 'instagram', 'x', 'linkedin']
    }
  };
});

return posts;

// Preparar post para Blotato scheduling
const post = $('Batch Posts').first().json;
const imageData = $json.predictions ? $json.predictions[0].bytesBase64Encoded : null;

// Calcular datetime ISO para scheduling
const scheduledDateTime = post.scheduled_date + 'T' + post.scheduled_time + '-06:00'; // CST

return [{
  json: {
    ...post,
    image_base64: imageData,
    scheduled_datetime: scheduledDateTime
  }
}];
